import { getNumberParser } from '../../parser/getNumberParser.js';
import type {
  SimpleFilterFieldNode,
  SimpleFilterFieldTree,
} from '../../types/conversion-tree-nodes.js';
/**
 * Conversion util that converts a filter field tree into a string.
 * @param tree - Filter field tree
 * @public
 */
export function convertFilterFieldTreeToString(
  tree?: SimpleFilterFieldTree,
): string {
  return _convertFilterFieldTreeToString(tree, '');
}

function getOperatorInfo(
  operatorValue: string,
  operatorType: string,
): {
  textValue: string;
  positionOperator: string;
} {
  const operatorInfo = {
    textValue: operatorValue,
    positionOperator: '',
  };

  switch (operatorValue) {
    case 'ends-with':
    case 'starts-with':
    case 'contains':
      operatorInfo.textValue = '=';
      operatorInfo.positionOperator = operatorValue;
      break;
    case 'not-ends-with':
    case 'not-starts-with':
    case 'not-contains':
      operatorInfo.textValue = '!=';
      operatorInfo.positionOperator = operatorValue.substring(4);
      break;
    case 'matches-phrase':
      operatorInfo.textValue = '~';
      break;
    case 'not-matches-phrase':
      operatorInfo.textValue = '!~';
      break;
    case 'search':
      operatorInfo.textValue = '* ~';
      break;
  }

  if (operatorType === 'ExistsOperator') {
    operatorInfo.textValue = operatorValue ? '= *' : '!= *';
  }

  if (operatorType === 'SearchOperator') {
    operatorInfo.textValue = '* ~';
  }

  return operatorInfo;
}

/**
 * check if the value has to be wrapped in quotes regardless if it contains a reserved character.
 * this is the case if it is either an empty string or if it is a boolean, number or duration but has
 * the type 'String' (then it has to be escaped, otherwise the type of the value would change)
 */
function hasToBeWrappedInQuotes(
  value: string,
  isString: boolean, // whether the nodeType equals 'String'
  hasPositionOperator: string | undefined,
): boolean {
  const numberParser = getNumberParser();
  const valueAsNumber = numberParser.parse(value);
  const durationRegex = /^\d+(ns|ms|s|m|h|d)$/;
  return (
    value === '' ||
    ((value === 'true' || value === 'false') && isString) ||
    (!isNaN(valueAsNumber) && isString && !hasPositionOperator) ||
    (durationRegex.test(value) && isString && !hasPositionOperator) ||
    (value.charAt(0) === '$' && isString)
  );
}

function getNestedValue({
  value: _value,
  textValue,
  nodeType,
  isFreeText,
  positionOperator,
  separator,
}: {
  value: SimpleFilterFieldNode[] | undefined | string | number | boolean;
  textValue?: string;
  nodeType:
    | 'Error'
    | 'String'
    | 'Variable'
    | 'List'
    | 'Key'
    | 'JSONPath'
    | 'Number'
    | 'BigInt'
    | 'Boolean'
    | 'Duration'
    | 'ComparisonOperator'
    | 'IPAddress'
    | 'UID'
    | 'SmartscapeId'
    | 'Timestamp'
    | 'ExistsOperator'
    | 'SearchOperator'
    | 'InclusionOperator'
    | 'Group';
  isFreeText?: boolean;
  positionOperator?: string;
  separator?: string;
}): string {
  let value = _value;
  if (value === undefined) {
    return '';
  }

  if (Array.isArray(value)) {
    let combinedString = '';

    // Recursively convert all included nodes.
    value.forEach((node, index) => {
      return (combinedString = _convertFilterFieldTreeToString(
        node,
        separator && index !== 0
          ? `${combinedString}${separator}`
          : combinedString,
      ));
    });

    return combinedString;
  }

  if (textValue) {
    // Remove leading '*' or the star in '"*' if position operator is 'contains' or 'ends-with'
    if (positionOperator === 'contains' || positionOperator === 'ends-with') {
      textValue = textValue.replaceAll(/(?<=^")\*|^\*/g, '');
    }

    // Remove trailing '*' or the star in '*"' if position operator is 'contains' or 'starts-with'
    if (positionOperator === 'contains' || positionOperator === 'starts-with') {
      textValue = textValue.replaceAll(/\*(?="$)|\*$/g, '');
    }

    return textValue;
  }

  value = `${value}`;

  // If the node is an error, we don't escape any characters
  if (nodeType === 'Error') {
    if (!isFreeText) {
      return value;
    }

    return value.replaceAll(/\\/g, '\\\\');
  }

  const wrapInQuotes = hasToBeWrappedInQuotes(
    value,
    nodeType === 'String',
    positionOperator,
  );

  // Escape the escape character ('\') with an escape character so it is included in the value, not just
  // escaping the next character
  value = value.replaceAll(/\\/g, '\\\\');

  // Escape double quotes with an escape character as it cannot be escaped with double quotes
  value = value.replaceAll(/"/g, '\\"');

  // Escape '*' symbols with an escape character as it may change the meaning of the syntax tree if escaped with double quotes
  const positionOperatorInValueRegex = /\*/g;
  value = value.replaceAll(positionOperatorInValueRegex, '\\*');

  // check if it contains any reserved characters
  // https://regex101.com/r/iw2j1u/1
  const reservedCharactersRegex =
    /(?!^\$)(?<!\\)(?:\\\\)*[,()!<>="$:[\]~ ]|\\$/;

  if (reservedCharactersRegex.test(value) || wrapInQuotes) {
    return `"${value}"`;
  }

  return value;
}

function _convertFilterFieldTreeToString(
  tree: SimpleFilterFieldTree | SimpleFilterFieldNode = undefined,
  convertedString: string = '',
): string {
  if (!tree) {
    return '';
  }

  switch (tree.type) {
    case 'Group': {
      let groupString = '';

      if (tree.explicit) {
        groupString = '(';
      }

      const childValues = getNestedValue({
        value: tree.children,
        nodeType: tree.type,
        separator: tree.explicitLogicalOperator
          ? ` ${tree.logicalOperator}`
          : '',
      });

      groupString =
        groupString +
        childValues +
        `${
          tree.children.length === 1 && tree.explicitLogicalOperator
            ? ' ' + tree.logicalOperator
            : ''
        }`;

      if (tree.explicit) {
        const lastChild = tree.children[tree.children.length - 1];

        // if the group is not missing a closing bracket add one to the string
        if (
          !(
            lastChild &&
            lastChild.type === 'Error' &&
            lastChild.value === '' &&
            tree.children.length !== 1
          )
        ) {
          groupString += ')';
        }
      }

      convertedString = addNodeToString(convertedString, groupString);

      break;
    }
    case 'Error':
      // if it is an empty group error the brackets were already added when handling the group
      if (tree.value !== '()') {
        convertedString = addNodeToString(
          convertedString,
          getNestedValue({
            value: tree.value,
            textValue: tree.textValue,
            nodeType: tree.type,
          }),
        );
      }
      break;
    case 'Statement': {
      let statement = '';
      const { key, comparisonOperator, value } = tree;

      if (key && key.type === 'JSONPath') {
        statement = `${key.value}${comparisonOperator || value ? ' ' : ''}`;
      } else if (key) {
        statement = `${getNestedValue({
          value: key.value,
          textValue: key.textValue,
          nodeType: key.type,
          isFreeText: !(comparisonOperator ?? value),
        })}${comparisonOperator || value ? ' ' : ''}`;
      }

      let operatorInfo = { textValue: '', positionOperator: '' };

      if (comparisonOperator) {
        operatorInfo = getOperatorInfo(
          comparisonOperator.value as string,
          comparisonOperator.type,
        );
        statement = `${statement}${operatorInfo.textValue}${value ? ' ' : ''}`;
      }

      if (value) {
        const val =
          value.type === 'Duration'
            ? `${value.value}${value.unit}`
            : value.value;

        const childValues = getNestedValue({
          value: val,
          textValue: value.textValue,
          nodeType: value.type,
          positionOperator: operatorInfo.positionOperator,
          separator: ',',
        });

        if (
          value.type === 'List' ||
          (value.type === 'Error' && Array.isArray(val))
        ) {
          statement = `${statement}(${childValues})`;
        } else if (value.type === 'Error') {
          statement = statement + childValues;
        } else {
          statement =
            statement +
            `${
              operatorInfo.positionOperator === 'contains' ||
              operatorInfo.positionOperator === 'ends-with'
                ? '*'
                : ''
            }` +
            childValues +
            `${
              operatorInfo.positionOperator === 'contains' ||
              operatorInfo.positionOperator === 'starts-with'
                ? '*'
                : ''
            }`;
        }
      }

      convertedString = addNodeToString(convertedString, statement);
      break;
    }
    case 'JSONPath': {
      convertedString = addNodeToString(convertedString, tree.value);
      break;
    }
    case 'Duration': {
      convertedString = addNodeToString(
        convertedString,
        `${tree.value}${tree.unit}`,
      );
      break;
    }
    default:
      convertedString = addNodeToString(
        convertedString,
        getNestedValue({
          value: tree.value,
          textValue: tree.textValue,
          nodeType: tree.type,
        }),
      );
      break;
  }

  return convertedString;
}

function addNodeToString(sourceString: string, insertionString: string) {
  if (insertionString) {
    const firstElement = sourceString === '' || sourceString === '(';
    return `${sourceString}${firstElement ? '' : ' '}${insertionString}`;
  }
  return sourceString;
}
